class Solution {
public:
    int countPrimeSetBits(vector<int>& nums) {
        int primes[]={2,3,5,7,11,13,17,19};
        auto isP=[&](int x){ for(int p:primes) if(p==x) return true; return false; };
        int ans=0;
        for(int x:nums) if(isP(__builtin_popcount(x))) ans++;
        return ans;
    }
};

