static int popc(int x){ int c=0; while(x){ c+=x&1; x>>=1; } return c; }
static int isPrimeBits(int x){ int ps[]={2,3,5,7,11,13,17,19}; for(int i=0;i<8;i++) if(ps[i]==x) return 1; return 0; }
int countPrimeSetBits(int* nums, int n) {
    int ans=0; for(int i=0;i<n;i++) if(isPrimeBits(popc(nums[i]))) ans++; return ans;
}
